prices_input = input().split(',')
prices = []
for price in prices_input:
    prices.append(int(price))

budget = int(input())
discount = int(input())

pairs = []
for i in range(len(prices)):
    for j in range(i + 1, len(prices)):
        total_cost = prices[i] + prices[j] - discount
        if total_cost <= budget:
            pair = (min(prices[i], prices[j]), max(prices[i], prices[j]))
            if pair not in pairs:
                pairs.append(pair)

pairs.sort()

for pair in pairs:
    print(pair)
